package com.example.api.config;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.UUID;

@Component
@Order(1)
public class RequestLoggingFilter extends OncePerRequestFilter {
    private static final Logger log = LoggerFactory.getLogger(RequestLoggingFilter.class);

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {
        String requestId = UUID.randomUUID().toString();
        long startTime = System.currentTimeMillis();

        log.info("Request started requestId={} method={} path={}", requestId, request.getMethod(), request.getRequestURI());
        try {
            filterChain.doFilter(request, response);
            long duration = System.currentTimeMillis() - startTime;
            log.info("Request completed requestId={} status={} durationMs={}", requestId, response.getStatus(), duration);
        } catch (Exception ex) {
            long duration = System.currentTimeMillis() - startTime;
            log.error("Request failed requestId={} method={} path={} durationMs={}", requestId, request.getMethod(), request.getRequestURI(), duration, ex);
            throw ex;
        }
    }
}

